type NavigateFunc = (to: string, options?: { replace?: boolean } | undefined) => void;

let _navigate: NavigateFunc | null = null;

export const setNavigate = (fn: NavigateFunc) => {
  _navigate = fn;
};

export const navigate = (to: string, options?: { replace?: boolean }) => {
  if (_navigate) {
    try {
      _navigate(to, options);
      return;
    } catch {
      // fallback to location change if react-router navigation fails
    }
  }

  if (options?.replace) {
    globalThis.location.replace(to);
  } else {
    globalThis.location.href = to;
  }
};

export const resetNavigate = () => {
  _navigate = null;
};

/**
 * notifications.ts — Singleton bridge to Ant Design's message/notification APIs.
 *
 * Ant Design v5 requires hook-based `App.useApp()` to display toasts inside the
 * theme context. This bridge captures those APIs once at mount (via
 * <NotificationBridge />) so non-React code (axios interceptors, utils) can
 * still trigger toasts.
 */

type MessageApi = {
  success: (content: string) => void;
  error: (content: string) => void;
  warning: (content: string) => void;
  info: (content: string) => void;
};

let messageApi: MessageApi | null = null;

export function registerMessageApi(api: MessageApi): void {
  messageApi = api;
}

export const notify = {
  success(content: string) {
    if (messageApi) messageApi.success(content);
  },
  error(content: string) {
    if (messageApi) messageApi.error(content);
  },
  warning(content: string) {
    if (messageApi) messageApi.warning(content);
  },
  info(content: string) {
    if (messageApi) messageApi.info(content);
  },
};

/**
 * httpClient.ts — Central axios client
 * - Factory `createApiClient(baseURL?)` that attaches:
 *   - withCredentials: true — sends HttpOnly cookies automatically
 *   - response interceptor: dispatches auth:loggedOut on 401 and redirects to login
 *
 * SECURITY: JWT is stored in HttpOnly cookie (not localStorage).
 * The browser sends the cookie automatically with `withCredentials: true`.
 */
import axios, { isAxiosError as axiosIsAxiosError } from "axios";
import { navigate } from "./navigation";
import { config } from "../../config/env";
import { notify } from "./notifications";

export function createApiClient(baseURL?: string) {
  const api = axios.create({
    baseURL,
    withCredentials: true, // Send HttpOnly cookies with every request
  });

  // Expose a small helper on the created instance so code that imports the
  // client as `axios` can still call `axios.isAxiosError(...)` safely.
  (api as unknown as Record<string, unknown>).isAxiosError = (error: unknown) => {
    try {
      return axiosIsAxiosError ? axiosIsAxiosError(error as Record<string, unknown>) : (error as Record<string, unknown>)?.isAxiosError === true;
    } catch {
      return (error as Record<string, unknown>)?.isAxiosError === true;
    }
  };

  // No request interceptor needed — HttpOnly cookie is sent automatically

  api.interceptors.response.use(
    (response) => response,
    (error) => {
      const status = error?.response?.status;
      const url = error?.config?.url;

      const urlStr = String(url || "");
      const isFormationApi =
        (config?.FORMATION_URL && urlStr.includes(config.FORMATION_URL)) || urlStr.includes("/formation/");

      if (status === 401) {
        if (isFormationApi) {
          return Promise.reject(error);
        }

        try {
          globalThis.dispatchEvent(new Event("auth:loggedOut"));
        } catch {
          /* ignore */
        }
        const isAlreadyOnLogin =
          globalThis.location.pathname === "/" ||
          globalThis.location.pathname.startsWith("/login") ||
          globalThis.location.pathname.startsWith("/auth");
        if (!isAlreadyOnLogin) {
          navigate("/", { replace: true });
        }
      } else if (error?.config?.meta?.silent !== true) {
        // Global UX feedback for unexpected errors. Callers can opt out by
        // passing { meta: { silent: true } } when they handle the error themselves.
        const serverMsg = error?.response?.data?.message;

        if (!error?.response) {
          notify.error("Pas de connexion au serveur. Vérifiez votre réseau.");
        } else if (status >= 500) {
          notify.error(serverMsg || "Erreur serveur. Réessayez dans un instant.");
        } else if (status === 403) {
          notify.warning(serverMsg || "Accès refusé.");
        } else if (status === 422) {
          notify.warning(serverMsg || "Données invalides ou insuffisantes.");
        }
        // 400/404/409 etc. are left to the caller for context-specific handling.
      }
      return Promise.reject(error);
    }
  );

  return api;
}

export const defaultApi = createApiClient();

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";
const API_URL = `${config.FORMATION_URL}/formation/departements`;

function normalizeListResponse<T>(payload: T[] | { content?: T[]; data?: T[]; items?: T[] }): T[] {
  if (Array.isArray(payload)) {
    return payload;
  }

  if (payload && typeof payload === "object") {
    const candidate = payload as { content?: unknown[]; data?: unknown[]; items?: unknown[] };
    if (Array.isArray(candidate.content)) {
      return candidate.content as T[];
    }
    if (Array.isArray(candidate.data)) {
      return candidate.data as T[];
    }
    if (Array.isArray(candidate.items)) {
      return candidate.items as T[];
    }
  }

  return [];
}

function isNotFoundError(error: unknown): boolean {
  return (error as { isAxiosError?: boolean; response?: { status?: number } })?.isAxiosError === true
    && (error as { response?: { status?: number } })?.response?.status === 404;
}

const DeptService = {
  async createDept(deptData: Record<string, unknown>) {
    try {
      const response = await axios.post(API_URL, deptData);
      return response.data;
    } catch (error: unknown) {
      throw error;
    }
  },

  async getAllDepts() {
    try {
      const response = await axios.get(API_URL);
      return normalizeListResponse(response.data);
    } catch (error: unknown) {
      if (isNotFoundError(error)) {
        return [];
      }
      throw error;
    }
  },

  async getDeptById(id: number | string) {
    try {
      const response = await axios.get(`${API_URL}/${id}`);
      return response.data;
    } catch (error: unknown) {
      throw error;
    }
  },

  async updateDept(id: number | string, deptData: Record<string, unknown>) {
    try {
      const response = await axios.put(`${API_URL}/${id}`, deptData);
      return response.data;
    } catch (error: unknown) {
      throw error;
    }
  },

  async deleteDept(id: number | string) {
    try {
      await axios.delete(`${API_URL}/${id}`);
    } catch (error: unknown) {
      throw error;
    }
  },

  async importDeptsExcel(file: File) {
    try {
      const formData = new FormData();
      formData.append("file", file);
      const response = await axios.post(`${API_URL}/import-excel`, formData);
      return response.data;
    } catch (error: unknown) {
      throw error;
    }
  },
};

export default DeptService;

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";

const API_URL = `${config.FORMATION_URL}/formation/ups`;

function normalizeListResponse<T>(payload: T[] | { content?: T[]; data?: T[]; items?: T[] }): T[] {
  if (Array.isArray(payload)) {
    return payload;
  }

  if (payload && typeof payload === "object") {
    const candidate = payload as { content?: unknown[]; data?: unknown[]; items?: unknown[] };
    if (Array.isArray(candidate.content)) {
      return candidate.content as T[];
    }
    if (Array.isArray(candidate.data)) {
      return candidate.data as T[];
    }
    if (Array.isArray(candidate.items)) {
      return candidate.items as T[];
    }
  }

  return [];
}

const UpService = {
  async createUp(upData: Record<string, unknown>) {
    const response = await axios.post(API_URL, upData);
    return response.data;
  },

  async getAllUps() {
    const response = await axios.get(API_URL);
    return normalizeListResponse(response.data);
  },

  async getUpById(id: number | string) {
    const response = await axios.get(`${API_URL}/${id}`);
    return response.data;
  },

  async updateUp(id: number | string, upData: Record<string, unknown>) {
    const response = await axios.put(`${API_URL}/${id}`, upData);
    return response.data;
  },

  async deleteUp(id: number | string) {
    await axios.delete(`${API_URL}/${id}`);
  },

  async importUpsExcel(file: File) {
    const formData = new FormData();
    formData.append("file", file);
    const response = await axios.post(`${API_URL}/import-excel`, formData, {
      headers: { "Content-Type": "multipart/form-data" },
    });
    return response.data;
  },
};

export default UpService;

import { createApiClient } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";
import type {
  AuthUser,
  EditProfileRequest,
  UpdatePasswordRequest,
} from "@/models/auth";

const API_URL = `${config.URL_ACCOUNT}/account`;

const api = createApiClient(API_URL);

export async function getAllAccounts(): Promise<AuthUser[]> {
  const response = await api.get<AuthUser[] | { content: AuthUser[] }>("/list-accounts");
  return response.data?.content || response.data || [];
}

export async function getProfile(): Promise<AuthUser> {
  const response = await api.get<AuthUser>("/profile");
  return response.data;
}

export async function editProfile(
  editProfileRequest: EditProfileRequest
): Promise<AuthUser> {
  const response = await api.post<AuthUser>("/edit-profile", editProfileRequest);
  return response.data;
}

export async function updatePassword(
  request: UpdatePasswordRequest
): Promise<unknown> {
  const res = await api.post("/update-password", request);
  return res.data;
}

export async function banAccount(userName: string): Promise<unknown> {
  const response = await api.post("/ban-account", null, { params: { userName } });
  return response.data;
}

export async function enableAccount(userName: string): Promise<unknown> {
  const response = await api.post("/enable-account", null, {
    params: { userName },
  });
  return response.data;
}

export async function deleteAccount(userId: string): Promise<unknown> {
  const response = await api.delete(`/delete/${userId}`);
  return response.data;
}

export async function updateAccount(
  userId: string,
  editProfileRequest: EditProfileRequest,
  role?: string
): Promise<AuthUser> {
  const params = role ? { role } : {};
  const response = await api.put<AuthUser>(
    `/update/${userId}`,
    editProfileRequest,
    { params }
  );
  return response.data;
}

export default {
  getAllAccounts,
  getProfile,
  editProfile,
  updatePassword,
  banAccount,
  enableAccount,
  deleteAccount,
  updateAccount,
};

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import FormationWorkflowService from "@/services/formation/FormationWorkflowService";
import DeptService from "@/services/formation/DeptService";
import UpService from "@/services/api/UploadService";
import { getAllAccounts } from "@/services/auth/AccountService";
import type { Formation } from "@/models/formation";
import type { Id } from "@/models/common";
import type { AuthUser } from "@/models/auth";

const KEYS = {
  all: ["formations"] as const,
  one: (id: Id) => ["formations", id] as const,
  visibles: ["formations", "visibles"] as const,
  achevees: ["formations", "achevees"] as const,
  withDocs: ["formations", "with-documents"] as const,
  byUp: (upId: Id) => ["formations", "up", upId] as const,
  byDept: (deptId: Id) => ["formations", "dept", deptId] as const,
  calendar: (enseignantId: Id) => ["formations", "calendar", enseignantId] as const,
  depts: ["departements"] as const,
};

export function useAllFormations() {
  return useQuery<Formation[]>({
    queryKey: KEYS.all,
    queryFn: () => FormationWorkflowService.getAllFormationWorkflows(),
  });
}

export function useFormationById(id: Id | undefined) {
  return useQuery<Formation>({
    queryKey: KEYS.one(id!),
    queryFn: () => FormationWorkflowService.getFormationWorkflowById(id!),
    enabled: !!id,
  });
}

export function useFormationsVisibles() {
  return useQuery<Formation[]>({
    queryKey: KEYS.visibles,
    queryFn: () => FormationWorkflowService.getFormationsVisibles(),
  });
}

export function useFormationsAchevees() {
  return useQuery<Formation[]>({
    queryKey: KEYS.achevees,
    queryFn: () => FormationWorkflowService.getFormationsAchevees(),
  });
}

export function useFormationsWithDocuments() {
  return useQuery<Formation[]>({
    queryKey: KEYS.withDocs,
    queryFn: () => FormationWorkflowService.getAllFormationWithDocuments(),
  });
}

export function useFormationsParUp(upId: Id | undefined) {
  return useQuery<Formation[]>({
    queryKey: KEYS.byUp(upId!),
    queryFn: () => FormationWorkflowService.getFormationsParUp(upId!),
    enabled: !!upId,
  });
}

export function useFormationsParDepartement(deptId: Id | undefined) {
  return useQuery<Formation[]>({
    queryKey: KEYS.byDept(deptId!),
    queryFn: () => FormationWorkflowService.getFormationsParDepartement(deptId!),
    enabled: !!deptId,
  });
}

export function useFormationsForCalendar(enseignantId: Id | undefined) {
  return useQuery<Formation[]>({
    queryKey: KEYS.calendar(enseignantId!),
    queryFn: () => FormationWorkflowService.getFormationsForCalendar(enseignantId!),
    enabled: !!enseignantId,
  });
}

export function useCreateFormation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (data: Record<string, unknown>) =>
      FormationWorkflowService.createFormationWorkflow(data),
    onSuccess: () => qc.invalidateQueries({ queryKey: KEYS.all }),
  });
}

export function useUpdateFormation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id: Id; data: Record<string, unknown> }) =>
      FormationWorkflowService.updateFormationWorkflow(id, data),
    onSuccess: (_, { id }) => {
      qc.invalidateQueries({ queryKey: KEYS.all });
      qc.invalidateQueries({ queryKey: KEYS.one(id) });
    },
  });
}

export function useDeleteFormation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: Id) => FormationWorkflowService.deleteFormationWorkflow(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: KEYS.all }),
  });
}

export function useUpdateInscriptionsOuvertes() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, ouvert }: { id: Id; ouvert: boolean }) =>
      FormationWorkflowService.updateInscriptionsOuvertes(id, ouvert),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: KEYS.all });
      qc.invalidateQueries({ queryKey: KEYS.visibles });
    },
  });
}

export function useDepartements() {
  return useQuery<unknown[]>({
    queryKey: KEYS.depts,
    queryFn: () => DeptService.getAllDepts(),
  });
}

export function useUps() {
  return useQuery<unknown[]>({
    queryKey: ["ups"],
    queryFn: () => UpService.getAllUps(),
  });
}

export function useAllAccounts() {
  return useQuery<AuthUser[]>({
    queryKey: ["accounts"],
    queryFn: () => getAllAccounts(),
  });
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import OneDriveService from "@/services/api/OneDriveService";

export function useDriveHierarchy() {
  return useQuery<unknown>({
    queryKey: ["onedrive", "hierarchy"],
    queryFn: () => OneDriveService.getDriveHierarchy(),
  });
}

export function useFormationHierarchy(idFormation: number | string | undefined) {
  return useQuery<unknown>({
    queryKey: ["onedrive", "formation-hierarchy", idFormation],
    queryFn: () => OneDriveService.getFormationHierarchy(idFormation!),
    enabled: !!idFormation,
  });
}

export function useDownloadOneDriveFile() {
  return useMutation({
    mutationFn: ({
      nomFormation,
      nomDocument,
      originalFileName,
    }: {
      nomFormation: string;
      nomDocument: string;
      originalFileName: string;
    }) => OneDriveService.downloadFile(nomFormation, nomDocument, originalFileName),
  });
}

export function useDeleteOneDriveFile() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({
      nomFormation,
      nomDocument,
      originalFileName,
    }: {
      nomFormation: string;
      nomDocument: string;
      originalFileName: string;
    }) => OneDriveService.deleteFile(nomFormation, nomDocument, originalFileName),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["onedrive"] }),
  });
}

export function useGetEmbedLink() {
  return useMutation({
    mutationFn: ({
      nomFormation,
      nomDocument,
    }: {
      nomFormation: string;
      nomDocument: string;
    }) => OneDriveService.getEmbedLink(nomFormation, nomDocument),
  });
}

import { useEffect, useState, useCallback, useMemo } from "react";
import {
  Layout,
  Row,
  Col,
  Button,
  Input,
  DatePicker,
  Tree,
  Modal,
  List,
  notification,
  Typography,
  Space,
  Card,
  Spin,
  Tag,
  Statistic,
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  FolderOpenOutlined,
  FileOutlined,
  ReloadOutlined,
  SearchOutlined,
  ApartmentOutlined,
  FileTextOutlined,
  EyeOutlined,
  CloudServerOutlined,
  AppstoreOutlined,
  PartitionOutlined,
  FilePdfOutlined,
  FileWordOutlined,
  FileExcelOutlined,
  FilePptOutlined,
  FileImageOutlined,
  FileZipOutlined,
  CalendarOutlined,
  InboxOutlined,
  FolderOutlined,
  PictureOutlined,
} from "@ant-design/icons";
import { useFormationsWithDocuments } from "@/hooks/formation/useFormations";
import { useFormationHierarchy } from "@/hooks/api/useOneDrive";
import DocumentViewer from "./DocumentViewer";
import DocumentListModal from "./DocumentListModal";
import DocumentUploadPanel from "./DocumentUploadPanel";
import "@/styles/pages/combined-formation-one-drive-tree.css";

const { Title, Text, Paragraph } = Typography;
const { Search } = Input;
const { RangePicker } = DatePicker;

const normalizeText = (value) => String(value ?? "").toLowerCase();

const formatFileSize = (value) => {
  const size = Number(value);
  if (!Number.isFinite(size) || size <= 0) return "Taille inconnue";
  if (size < 1024) return `${size} o`;
  if (size < 1024 * 1024) return `${(size / 1024).toFixed(1)} Ko`;
  return `${(size / (1024 * 1024)).toFixed(1)} Mo`;
};

const formatDate = (value) => {
  if (!value) return "Date inconnue";
  try {
    return new Intl.DateTimeFormat("fr-FR", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    }).format(new Date(value));
  } catch {
    return String(value).split("T")[0];
  }
};

function DocEmpty({ variant = "default", icon, title, text }) {
  let variantClass = "";
  if (variant === "tree") variantClass = " doc-empty-icon--tree";
  else if (variant === "preview") variantClass = " doc-empty-icon--preview";
  return (
    <div className="doc-empty">
      <div className={`doc-empty-icon${variantClass}`}>{icon}</div>
      {title && <div className="doc-empty-title">{title}</div>}
      <div className="doc-empty-text">{text}</div>
    </div>
  );
}

const getFileIcon = (name) => {
  const ext = String(name || "").split(".").pop()?.toLowerCase();
  if (["pdf"].includes(ext)) return <FilePdfOutlined style={{ color: "#dc2626" }} />;
  if (["doc", "docx"].includes(ext)) return <FileWordOutlined style={{ color: "#1d4ed8" }} />;
  if (["xls", "xlsx", "csv"].includes(ext)) return <FileExcelOutlined style={{ color: "#047857" }} />;
  if (["ppt", "pptx"].includes(ext)) return <FilePptOutlined style={{ color: "#c2410c" }} />;
  if (["png", "jpg", "jpeg", "gif", "webp", "svg"].includes(ext)) return <FileImageOutlined style={{ color: "#7c3aed" }} />;
  if (["zip", "rar", "7z", "tar", "gz"].includes(ext)) return <FileZipOutlined style={{ color: "#b45309" }} />;
  return <FileTextOutlined style={{ color: "#475569" }} />;
};

const toTreeNode = (node) => ({
  title: node.name,
  key: node.id,
  icon: node.folder ? <FolderOpenOutlined /> : <FileOutlined />,
  isLeaf: !node.folder,
  children: node.children?.map(toTreeNode),
  raw: node,
});

export default function CombinedFormationOneDriveTree() {
  const [formations, setFormations] = useState([]);
  const [filteredFormations, setFilteredFormations] = useState([]);
  const [selectedFormation, setSelectedFormation] = useState(null);
  const [treeData, setTreeData] = useState([]);
  const [expandedKeys, setExpandedKeys] = useState([]);
  const [selectedFile, setSelectedFile] = useState(null);
  const [uploadModalVisible, setUploadModalVisible] = useState(false);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [searchText, setSearchText] = useState("");
  const [dateRange, setDateRange] = useState([]);
  const { data: formationsData = [], isLoading: formationsLoading } = useFormationsWithDocuments();

  useEffect(() => {
    let list;
    if (Array.isArray(formationsData)) { list = formationsData; }
    else if (formationsData) { list = [formationsData]; }
    else { list = []; }
    setFormations(list);
    setFilteredFormations(list);
  }, [formationsData]);

  useEffect(() => {
    let result = formations;
    const txt = normalizeText(searchText).trim();

    if (txt) {
      result = result.filter((formation) => {
        const title = normalizeText(formation.titreFormation);
        const start = normalizeText(formatDate(formation.dateDebut));
        const up = normalizeText(formation.up1?.libelle);
        const dept = normalizeText(formation.departement1?.libelle);
        const documents = normalizeText(
          String(formation.documents?.length ?? 0)
        );

        return (
          title.includes(txt) ||
          start.includes(txt) ||
          up.includes(txt) ||
          dept.includes(txt) ||
          documents.includes(txt)
        );
      });
    }

    if (dateRange.length === 2) {
      const [from, to] = dateRange;
      result = result.filter((formation) => {
        const debut = formation.dateDebut ? String(formation.dateDebut).split("T")[0] : "";
        return debut >= from.format("YYYY-MM-DD") && debut <= to.format("YYYY-MM-DD");
      });
    }

    setFilteredFormations(result);
  }, [searchText, dateRange, formations]);

  const selectedFormationStats = useMemo(() => {
    const documents = selectedFormation?.documents ?? [];
    const folders = treeData.filter((node) => !node.isLeaf).length;

    return {
      documentCount: documents.length,
      treeRoots: treeData.length,
      folders,
    };
  }, [selectedFormation, treeData]);

  const { data: hierarchyData, isLoading: treeLoading, refetch: refetchHierarchy } = useFormationHierarchy(selectedFormation?.idFormation);

  useEffect(() => {
    if (!selectedFormation) {
      setTreeData([]);
      setExpandedKeys([]);
      setSelectedFile(null);
      return;
    }

    if (hierarchyData) {
      const nodes = Array.isArray(hierarchyData) ? hierarchyData : [];
      setTreeData(nodes.map(toTreeNode));
      setExpandedKeys(nodes.map((node) => node.id));
      setSelectedFile(null);
    } else if (!treeLoading) {
      setTreeData([]);
      setExpandedKeys([]);
    }
  }, [hierarchyData, treeLoading, selectedFormation]);

  const onSelectTree = (_, { node }) => {
    if (!node.isLeaf) return;
    const { raw } = node;
    setSelectedFile({
      name: raw.name,
      fileSize: raw.fileSize,
      downloadUrl: raw.downloadUrl,
      rawUrl: raw.downloadUrl,
    });
  };

  const handleAddSuccess = () => {
    notification.success({ message: "Document ajouté" });
    loadTree();
  };

  const handleEditSuccess = () => {
    notification.success({ message: "Documents mis à jour" });
    loadTree();
  };

  const openFormation = (formation) => {
    setSelectedFormation(formation);
    setSelectedFile(null);
  };

  return (
    <Layout className="doc-page">
      <Card
        variant="borderless"
        className="doc-hero"
        styles={{ body: { padding: 28 } }}
      >
        <Space direction="vertical" size={10} style={{ width: "100%" }}>
          <Tag className="doc-hero-tag">Dossiers & documents de formation</Tag>
          <Title level={2} className="doc-hero-title">
            <span className="doc-hero-icon">
              <CloudServerOutlined />
            </span>
            {" "}Explorer les formations et leurs dossiers
          </Title>
          <Paragraph className="doc-hero-subtitle">
            Sélectionnez une formation, parcourez son arborescence OneDrive et ouvrez un document en aperçu sans quitter la page.
          </Paragraph>
        </Space>

        <Row gutter={[16, 16]} className="doc-stat-strip">
          <Col xs={24} md={8}>
            <Card variant="borderless" className="doc-stat-card doc-stat-card--blue">
              <Statistic
                title="Formations disponibles"
                value={filteredFormations.length}
                prefix={<ApartmentOutlined />}
              />
            </Card>
          </Col>
          <Col xs={24} md={8}>
            <Card variant="borderless" className="doc-stat-card doc-stat-card--indigo">
              <Statistic
                title="Documents indexés"
                value={selectedFormationStats.documentCount}
                prefix={<FileTextOutlined />}
              />
            </Card>
          </Col>
          <Col xs={24} md={8}>
            <Card variant="borderless" className="doc-stat-card doc-stat-card--violet">
              <Statistic
                title="Dossiers affichés"
                value={selectedFormationStats.treeRoots}
                prefix={<FolderOpenOutlined />}
              />
            </Card>
          </Col>
        </Row>
      </Card>

      <Card variant="outlined" className="doc-toolbar">
        <Space wrap size={12} style={{ width: "100%", justifyContent: "space-between" }}>
          <Space wrap size={12}>
            <Search
              placeholder="Rechercher une formation, un département, une UP ou un document"
              allowClear
              value={searchText}
              onChange={(event) => setSearchText(event.target.value)}
              onSearch={setSearchText}
              prefix={<SearchOutlined />}
              style={{ width: 380, maxWidth: "100%" }}
            />
            <RangePicker
              onChange={setDateRange}
              suffixIcon={<CalendarOutlined />}
              getPopupContainer={(triggerNode) => triggerNode?.parentNode ?? document.body}
            />
          </Space>

          <Space wrap size={8}>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              disabled={!selectedFormation}
              onClick={() => setUploadModalVisible(true)}
              className="doc-btn-add"
            >
              Ajouter un document
            </Button>
            <Button
              icon={<EditOutlined />}
              disabled={!selectedFormation}
              onClick={() => setEditModalVisible(true)}
              className="doc-btn-manage"
            >
              Gérer les documents
            </Button>
            <Button
              icon={<ReloadOutlined />}
              onClick={refetchHierarchy}
              disabled={!selectedFormation}
              className="doc-btn-refresh"
            >
              Rafraîchir
            </Button>
          </Space>
        </Space>
      </Card>

      <Row gutter={[20, 20]}>
        <Col xs={24} xl={7}>
          <Card
            variant="outlined"
            className="doc-panel"
            title={
              <span className="doc-panel-title">
                <span className="doc-panel-title-icon"><AppstoreOutlined /></span>
                {" "}Formations
              </span>
            }
            extra={<span className="doc-count-chip">{filteredFormations.length} résultat(s)</span>}
          >
            <Spin spinning={formationsLoading}>
              {filteredFormations.length > 0 ? (
                <List
                  size="small"
                  dataSource={filteredFormations}
                  renderItem={(formation) => {
                    const isSelected = selectedFormation?.idFormation === formation.idFormation;
                    const docCount = formation.documents?.length ?? 0;

                    return (
                      <List.Item
                        key={formation.idFormation}
                        onClick={() => openFormation(formation)}
                        className={`doc-formation-item${isSelected ? " doc-formation-item--selected" : ""}`}
                      >
                        <Space direction="vertical" size={8} style={{ width: "100%" }}>
                          <Space align="start" style={{ width: "100%", justifyContent: "space-between" }}>
                            <div>
                              <Text strong className="doc-formation-title">
                                {formation.titreFormation || "Formation sans titre"}
                              </Text>
                              <br />
                              <Text className="doc-formation-date">
                                <CalendarOutlined style={{ marginInlineEnd: 6 }} />
                                {formatDate(formation.dateDebut)}
                              </Text>
                            </div>
                            <Button
                              type="text"
                              icon={<EditOutlined />}
                              onClick={(event) => {
                                event.stopPropagation();
                                openFormation(formation);
                                setEditModalVisible(true);
                              }}
                            />
                          </Space>

                          <Space wrap size={8}>
                            <Tag color="blue" bordered={false}>{formation.up1?.libelle || "UP inconnue"}</Tag>
                            <Tag color="green" bordered={false}>{formation.departement1?.libelle || "Département inconnu"}</Tag>
                            <Tag color={docCount > 0 ? "geekblue" : "default"} bordered={false}>
                              <FileTextOutlined style={{ marginInlineEnd: 4 }} />
                              {docCount} document(s)
                            </Tag>
                          </Space>
                        </Space>
                      </List.Item>
                    );
                  }}
                />
              ) : (
                <DocEmpty
                  icon={<InboxOutlined />}
                  title="Aucune formation"
                  text="Aucune formation ne correspond à votre recherche"
                />
              )}
            </Spin>
          </Card>
        </Col>

        <Col xs={24} xl={8}>
          <Card
            variant="outlined"
            className="doc-panel"
            title={
              <span className="doc-panel-title doc-panel-title--tree">
                <span className="doc-panel-title-icon"><PartitionOutlined /></span>
                {" "}Arborescence OneDrive
              </span>
            }
            extra={selectedFormation ? <span className="doc-status-chip doc-status-chip--active">Formation sélectionnée</span> : null}
          >
            {selectedFormation ? (
              <>
                <div className="doc-selected-summary">
                  <span className="doc-selected-summary-avatar">
                    <FolderOpenOutlined />
                  </span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 600, color: "#0f172a", fontSize: 14 }}>
                      {selectedFormation.titreFormation}
                    </div>
                    <div style={{ fontSize: 12.5, color: "#64748b", marginTop: 2 }}>
                      {selectedFormation.up1?.libelle || "UP inconnue"} · {selectedFormation.departement1?.libelle || "Département inconnu"}
                    </div>
                  </div>
                </div>

                {(() => {
                  if (treeLoading) return (
                    <div style={{ minHeight: 240, display: "grid", placeItems: "center" }}>
                      <Spin size="large" />
                    </div>
                  );
                  if (treeData.length > 0) return (
                    <div className="doc-tree-wrapper">
                      <Tree
                        showIcon
                        blockNode
                        treeData={treeData}
                        expandedKeys={expandedKeys}
                        onExpand={setExpandedKeys}
                        onSelect={onSelectTree}
                      />
                    </div>
                  );
                  return (
                    <DocEmpty
                      variant="tree"
                      icon={<FolderOutlined />}
                      title="Aucun dossier"
                      text="Aucun dossier n'est disponible pour cette formation"
                    />
                  );
                })()}
              </>
            ) : (
              <DocEmpty
                variant="tree"
                icon={<PartitionOutlined />}
                title="Aucune formation sélectionnée"
                text="Sélectionnez une formation pour voir ses dossiers"
              />
            )}
          </Card>
        </Col>

        <Col xs={24} xl={9}>
          <Card
            variant="outlined"
            className="doc-panel"
            title={
              <span className="doc-panel-title doc-panel-title--preview">
                <span className="doc-panel-title-icon"><EyeOutlined /></span>
                {" "}Prévisualisation
              </span>
            }
            extra={selectedFile ? <span className="doc-status-chip doc-status-chip--ready">Document prêt</span> : null}
          >
            {selectedFile ? (
              <Space direction="vertical" size={12} style={{ width: "100%" }}>
                <Card
                  variant="borderless"
                  className="doc-file-card"
                  styles={{ body: { padding: 16 } }}
                >
                  <Space align="start" size={14} style={{ width: "100%" }}>
                    <span className="doc-file-icon">{getFileIcon(selectedFile.name)}</span>
                    <Space direction="vertical" size={6} style={{ flex: 1, minWidth: 0 }}>
                      <Text strong className="doc-file-name">
                        {selectedFile.name}
                      </Text>
                      <Text type="secondary">{formatFileSize(selectedFile.fileSize)}</Text>
                      <Button
                        type="primary"
                        href={selectedFile.downloadUrl}
                        target="_blank"
                        icon={<EyeOutlined />}
                        rel="noopener noreferrer"
                        className="doc-btn-open"
                      >
                        Ouvrir / télécharger
                      </Button>
                    </Space>
                  </Space>
                </Card>

                <DocumentViewer
                  url={selectedFile.rawUrl}
                  ext={selectedFile.name.split(".").pop()}
                />
              </Space>
            ) : (
              <DocEmpty
                variant="preview"
                icon={<PictureOutlined />}
                title="Aucun aperçu"
                text="Sélectionnez un fichier dans l'arborescence pour l'aperçu"
              />
            )}
          </Card>
        </Col>
      </Row>

      <Modal
        title={selectedFormation ? `Ajouter à ${selectedFormation.titreFormation}` : "Ajouter un document"}
        open={uploadModalVisible}
        onCancel={() => setUploadModalVisible(false)}
        footer={null}
        width={720}
        destroyOnHidden
      >
        {selectedFormation && (
          <DocumentUploadPanel
            formationId={selectedFormation.idFormation}
            onDocumentAdded={() => {
              handleAddSuccess();
              setUploadModalVisible(false);
            }}
            onClose={() => setUploadModalVisible(false)}
          />
        )}
      </Modal>

      {selectedFormation && (
        <DocumentListModal
          open={editModalVisible}
          formation={selectedFormation}
          onClose={() => setEditModalVisible(false)}
          onDocumentsUpdated={() => {
            handleEditSuccess();
            setEditModalVisible(false);
          }}
        />
      )}
    </Layout>
  );
}
